import SwiftUI
import BioAuthKit

class SecurityManager {
    private let bioAuthenticator = BioAuthenticator()
    private var session: BioAuthSession?

    func startPassiveAuthentication() async {
        do {
            let isAvailable = await bioAuthenticator.isServiceAvailable(.continuousHeartRhythm)
            guard isAvailable else {
                print("Continuous authentication not available.")
                return
            }
            self.session = try await bioAuthenticator.startSession(policy: .continuousHeartRhythm)
            print("BioAuth session started successfully.")
        } catch {
            print("Failed to start BioAuth session: \(error.localizedDescription)")
        }
    }

    func stopPassiveAuthentication() {
        session?.invalidate()
        session = nil
        print("BioAuth session stopped.")
    }
}

