// Define the query that allows searching
struct LocationQuery: EntityQuery, EntityStringQuery {
    // Fetches specific locations from IDs
    func entities(for identifiers: [String]) async throws -> [LocationEntity] {
        // Your logic to resolve IDs to locations
        return []
    }

    // Main search function
    func entities(matching string: String) async throws -> [LocationEntity] {
        // Use CLGeocoder or a weather API to find locations matching the string
        let geocoder = CLGeocoder()
        let placemarks = try await geocoder.geocodeAddressString(string)
        return placemarks.compactMap { placemark in
            guard let name = placemark.name, let location = placemark.location else { return nil }
            return LocationEntity(id: "\(location.coordinate.latitude),\(location.coordinate.longitude)", name: name, coordinate: location.coordinate)
        }
    }
