import HealthKit

class HealthManager {
    private let healthStore = HKHealthStore()

    // New identifier for iOS26
    private let mentalAcuityType = HKQuantityType.quantityType(forIdentifier: .mentalAcuityScore)!

    func requestAuthorization() async throws {
        try await healthStore.requestAuthorization(toShare: [], read: [mentalAcuityType])
    }

    func fetchLatestAcuityScore() async throws -> Double? {
        let descriptor = HKSampleQueryDescriptor(predicates: [.quantitySample(type: mentalAcuityType)],
                                                 sortDescriptors: [SortDescriptor(\.endDate, order: .reverse)],
                                                 limit: 1)
        let results = try await descriptor.result(for: healthStore)
        guard let latestSample = results.first else { return nil }

        // Score is a value from 0.0 to 1.0
        return latestSample.quantity.doubleValue(for: .percent())
    }
}

