// 1. The Timeline Entry
struct SimpleEntry: TimelineEntry {
    let date: Date
}

// 2. The Timeline Provider
struct Provider: TimelineProvider {
    // Provides a generic version of the widget for the widget gallery.
    func placeholder(in context: Context) -> SimpleEntry {
        SimpleEntry(date: Date())
    }

    // Provides a snapshot for a transient situation (e.g., when the user is choosing the widget).
    func getSnapshot(in context: Context, completion: @escaping (SimpleEntry) -> ()) {
        let entry = SimpleEntry(date: Date())
        completion(entry)
    }

    // Provides the timeline of entries for the widget to display.
    func getTimeline(in context: Context, completion: @escaping (Timeline<Entry>) -> ()) {
        let entries = [SimpleEntry(date: Date())]
        // Refresh the timeline after one hour.
        let nextUpdate = Calendar.current.date(byAdding: .hour, value: 1, to: Date())!
        let timeline = Timeline(entries: entries, policy: .after(nextUpdate))
        completion(timeline)
    }
}

