import SpatialBroadcast
import AVFoundation

class AudioBroadcaster {
    private let broadcastSession = SBCoordinatedAudioSession()
    private var player: AVPlayer?

    func setupBroadcast(with audioURL: URL) {
        let playerItem = AVPlayerItem(url: audioURL)
        self.player = AVPlayer(playerItem: playerItem)
    }

    func startBroadcasting() async {
        guard let player = player else { return }
        do {
            // Begins broadcasting the audio from the player to nearby listeners.
            // No manual pairing is required.
            try await broadcastSession.broadcast(player)
            player.play()
        } catch {
            print("Failed to start broadcast: \(error.localizedDescription)")
        }
    }

    func stopBroadcasting() {
        broadcastSession.invalidate()
        player?.pause()
    }
}

